);
	reg resetn = 0;

	always @(posedge clk)
		resetn <= 1;

	wire        cpu0_trap;
	wire        cpu0_mem_valid;
	wire        cpu0_mem_instr;
	wire        cpu0_mem_ready;
	wire [31:0] cpu0_mem_addr;
	wire [31:0] cpu0_mem_wdata;
	wire [3:0]  cpu0_mem_wstrb;
	wire [31:0] cpu0_mem_rdata;
	wire        cpu0_trace_valid;
	wire [35:0] cpu0_trace_data;

	wire        cpu1_trap;
	wire        cpu1_mem_valid;
	wire        cpu1_mem_instr;
	wire        cpu1_mem_ready;
	wire [31:0] cpu1_mem_addr;
	wire [31:0] cpu1_mem_wdata;
