		.pcpi_wr     (pcpi_wr         ),
		.pcpi_rd     (pcpi_rd         ),
		.pcpi_wait   (pcpi_wait       ),
		.pcpi_ready  (pcpi_ready      ),
		.trace_valid (cpu0_trace_valid),
		.trace_data  (cpu0_trace_data )
	);

	picorv32 #(
		.ENABLE_COUNTERS(0),
		.REGS_INIT_ZERO(1),
		.COMPRESSED_ISA(1),
		.ENABLE_TRACE(1),

		.TWO_STAGE_SHIFT(1),
